-- round41_navigation_items_english.sql
-- Adds editable English labels/descriptions for public navigation.

alter table navigation_items
  add column if not exists label_en text,
  add column if not exists description_en text;

update navigation_items
set label_en = case id
  when '10000000-0000-4000-8000-000000000001' then 'Home'
  when '10000000-0000-4000-8000-000000000002' then 'Admissions'
  when '10000000-0000-4000-8000-000000000003' then 'News'
  when '10000000-0000-4000-8000-000000000004' then 'About'
  when '10000000-0000-4000-8000-000000000005' then 'Programs'
  when '10000000-0000-4000-8000-000000000006' then 'Works'
  when '10000000-0000-4000-8000-000000000007' then 'Current Students'
  when '10000000-0000-4000-8000-000000000101' then 'About the Department'
  when '10000000-0000-4000-8000-000000000102' then 'Faculty and Staff'
  when '10000000-0000-4000-8000-000000000103' then 'Facilities and Laboratories'
  when '10000000-0000-4000-8000-000000000104' then 'Contact'
  when '10000000-0000-4000-8000-000000000201' then 'Undergraduate Program'
  when '10000000-0000-4000-8000-000000000202' then 'Graduate Program'
  when '10000000-0000-4000-8000-000000000301' then 'Student Works'
  when '10000000-0000-4000-8000-000000000302' then 'Faculty Works'
  when '10000000-0000-4000-8000-000000000401' then 'Registration'
  when '10000000-0000-4000-8000-000000000402' then 'Student Loan Fund'
  when '10000000-0000-4000-8000-000000000403' then 'Student Welfare'
  when '10000000-0000-4000-8000-000000000404' then 'Complaints and Feedback'
  when '10000000-0000-4000-8000-000000001001' then 'Home'
  when '10000000-0000-4000-8000-000000001002' then 'Admissions'
  when '10000000-0000-4000-8000-000000001003' then 'News'
  when '10000000-0000-4000-8000-000000001004' then 'About the Department'
  when '10000000-0000-4000-8000-000000001005' then 'Facilities and Laboratories'
  when '10000000-0000-4000-8000-000000001006' then 'Undergraduate Program'
  when '10000000-0000-4000-8000-000000001007' then 'Graduate Program'
  when '10000000-0000-4000-8000-000000002001' then 'Registration'
  when '10000000-0000-4000-8000-000000002002' then 'Student Loan Fund'
  when '10000000-0000-4000-8000-000000002003' then 'Student Welfare'
  when '10000000-0000-4000-8000-000000002004' then 'Complaints and Feedback'
  when '10000000-0000-4000-8000-000000002005' then 'Student Works'
  else label_en
end,
description_en = case id
  when '10000000-0000-4000-8000-000000000101' then 'Vision, Mission, and Highlights'
  when '10000000-0000-4000-8000-000000000102' then 'Lecturers and Staff'
  when '10000000-0000-4000-8000-000000000103' then 'Classrooms, Laboratories, and Learning Facilities'
  when '10000000-0000-4000-8000-000000000104' then 'Address and Map'
  when '10000000-0000-4000-8000-000000000201' then '4-Year Program'
  when '10000000-0000-4000-8000-000000000202' then '2-Year Program'
  when '10000000-0000-4000-8000-000000000301' then 'Theses and Awards'
  when '10000000-0000-4000-8000-000000000302' then 'Research and Publications'
  else description_en
end
where id in (
  '10000000-0000-4000-8000-000000000001',
  '10000000-0000-4000-8000-000000000002',
  '10000000-0000-4000-8000-000000000003',
  '10000000-0000-4000-8000-000000000004',
  '10000000-0000-4000-8000-000000000005',
  '10000000-0000-4000-8000-000000000006',
  '10000000-0000-4000-8000-000000000007',
  '10000000-0000-4000-8000-000000000101',
  '10000000-0000-4000-8000-000000000102',
  '10000000-0000-4000-8000-000000000103',
  '10000000-0000-4000-8000-000000000104',
  '10000000-0000-4000-8000-000000000201',
  '10000000-0000-4000-8000-000000000202',
  '10000000-0000-4000-8000-000000000301',
  '10000000-0000-4000-8000-000000000302',
  '10000000-0000-4000-8000-000000000401',
  '10000000-0000-4000-8000-000000000402',
  '10000000-0000-4000-8000-000000000403',
  '10000000-0000-4000-8000-000000000404',
  '10000000-0000-4000-8000-000000001001',
  '10000000-0000-4000-8000-000000001002',
  '10000000-0000-4000-8000-000000001003',
  '10000000-0000-4000-8000-000000001004',
  '10000000-0000-4000-8000-000000001005',
  '10000000-0000-4000-8000-000000001006',
  '10000000-0000-4000-8000-000000001007',
  '10000000-0000-4000-8000-000000002001',
  '10000000-0000-4000-8000-000000002002',
  '10000000-0000-4000-8000-000000002003',
  '10000000-0000-4000-8000-000000002004',
  '10000000-0000-4000-8000-000000002005'
